addEventListener('fetch', event => {
  event.respondWith(handleRequest(event.request))
})

async function handleRequest(request) {
  try {
    const url = new URL(request.url)
    if (url.pathname === '/sendEmail') {
      return await sendEmail(request)
    } else if (url.pathname === '/processPayment') {
      return await processPayment(request)
    } 
    // add more routes here...
    else {
      return new Response('Not found', { status: 404 })
    }
  } catch (error) {
    console.log(error)
    return new Response('Server Error', { status: 500 })
  }
}

async function sendEmail(request) {
  const { email, subject, body } = await request.json()
  
  // Validation
  if (!email || !subject || !body) {
    return new Response('Invalid Request', { status: 400 })
  }

  const sendgridKey = 'YOUR_SENDGRID_KEY'
  const response = await fetch(`https://api.sendgrid.com/v3/mail/send`, {
    method: 'POST',
    headers: {
      Authorization: `Bearer ${sendgridKey}`,
      'Content-Type': 'application/json'
    },
    body: JSON.stringify({
      personalizations: [
        {
          to: [{ email }]
        }
      ],
      from: { email: 'YOUR_EMAIL' },
      subject,
      content: [{ type: 'text/plain', value: body }]
    })
  })
  
  if (!response.ok) throw new Error(`HTTP error! status: ${response.status}`);

  return new Response('Email sent', { status: 200 })
}

async function processPayment(request) {
  const { cardNumber, expMonth, expYear, cvc } = await request.json()
  
  // Validation
  if (!cardNumber || !expMonth || !expYear || !cvc) {
    return new Response('Invalid Request', { status: 400 })
  }

  const stripeKey = 'YOUR_STRIPE_KEY'
  fetch('https://api.stripe.com/v1/tokens', {
    method: 'POST',
    headers: {
      Authorization: `Bearer ${stripeKey}`,
      'Content-Type': 'application/x-www-form-urlencoded'
    },
    body: new URLSearchParams({
      card: { number: cardNumber, exp_month: expMonth, exp_year: expYear, cvc } 
    })
  }).then(response => response.json())
     .then(data => console.log('Token generated: ', data))
     .catch(error => console.log('Error:', error));
  
  return new Response('Payment processing... (Not Implemented)', { status: 200 }) // Stripe should be used server-side to charge the card, not on client side.
}